--嗨皮用户使用小蚕情况统计
--老用户且0409前未下单
select
    count(1),
    sum(order_number),
    sum(cumulative_acquisition_service_fee)
from
    ads.ads_haipi_old_user_no_order_in_0409_22_00 as t1;
--新用户
select
    count(1),
    sum(order_number),
    sum(cumulative_acquisition_service_fee)
from
    ads.ads_haipi_new_user_in_0409_22_00 as t1;
--新用户拉新
select
    count(1),
    sum(order_number),
    sum(cumulative_acquisition_service_fee)
from
    ads.ads_haipi_new_user_pull_in_0409_22_00 as t1;



