--嗨皮未注册小蚕用户数量 39325

select
    count(t1.phone)
from
    ods.ods_haipi_user_phone as t1
left join
    dim.dim_client_user as t2
on
    t1.phone = t2.phone
where
    t2.phone is null;
--66789
select
    count(distinct t1.phone)
from
    ods.ods_haipi_user_phone as t1

--大熊未注册小蚕用户数量 39325

