select
    count(distinct t1.phone) as tot_user, -- 大熊用户量 
    count(distinct if(t2.phone is null,t1.phone,null)) as unregister_silkworm_user_num -- 未注册小蚕大熊用户量
from
    ods.ods_bear_user as t1
left join
    dim.dim_client_user as t2
on
    t1.phone = t2.phone;



-- 分渠道流量
-- 0=其他 1=短信入口 2=APP 3=h5 4=小程序 5=社群 6=朋友圈

-- 第三方用户点击
-- clickhouse SQL语法
-- click_type 0=其他 1=短信入口 2=APP 3=h5 4=小程序 5=社群 6=朋友圈
-- desc silkworm.third_platform_click_record

-- 大熊分渠道访问用户
select click_type,
    count(distinct silk_id) as user_num
from silkworm.third_platform_click_record
where toDate(created_at)=toDate(today())-1
    and platform_id =2 
group by click_type




-- 大熊用户红包领取和使用
select 
    count(a.silk_id) as get_num, -- 领取数
    count(if(b.user_id is not null,b.redpacket_id,null)) as used_num, -- 使用量
    sum(if(b.user_id is not null,a.red_pack_amount,0))/100 as used_redpacket_amt -- 使用红包金额
from ods.third_platform_user a -- 红包领取
left join dwd.dwd_hive_silkworm_redpack_user_red_pack b -- 红包使用
    on a.silk_id=b.user_id 
        and a.red_pack_id=b.redpacket_id 
        and b.redpacket_use_status=2 
        and concat(b.year,'-',LPAD(b.month,2,'0'),'-',LPAD(b.day,2,'0'))<='2024-05-14'
        and substring(b.used_time,1,10)<='2024-05-14' -- 使用时间限制
